/**
 * The [layout](https://developers.arcgis.com/javascript/latest/references/core/widgets/ValuePicker/#layout) of the [ValuePicker](https://developers.arcgis.com/javascript/latest/references/core/widgets/ValuePicker/) widget.
 *
 * @since 5.0
 */
export type Layout = "horizontal" | "vertical";

/**
 * The [animate](https://developers.arcgis.com/javascript/latest/references/core/widgets/ValuePicker/#event-animate) event of the [ValuePicker](https://developers.arcgis.com/javascript/latest/references/core/widgets/ValuePicker/) widget.
 *
 * @since 5.0
 */
export interface AnimateEvent {}

/**
 * The events emitted by the [ValuePicker](https://developers.arcgis.com/javascript/latest/references/core/widgets/ValuePicker/) widget.
 *
 * @since 5.0
 */
export interface ValuePickerViewModelEvents {
  /**
   * Fires when the ValuePicker is playing at an interval defined by [ValuePicker.playRate](https://developers.arcgis.com/javascript/latest/references/core/widgets/ValuePicker/#playRate).
   *
   * @since 5.0
   * @example
   * const valuePicker = new ValuePicker();
   * valuePicker.on("animate", () => {
   *   console.log("the animation timer is fired");
   * });
   */
  animate: AnimateEvent;
  /**
   * Fires when the ValuePicker's next button is clicked.
   *
   * @since 5.0
   * @example
   * const valuePicker = new ValuePicker();
   * valuePicker.on("next", () => {
   *   console.log("user clicked the next button");
   * });
   */
  next: void;
  /**
   * Fires when the ValuePicker's pause button is clicked.
   *
   * @since 5.0
   * @example
   * const valuePicker = new ValuePicker();
   * valuePicker.on("pause", () => {
   *   console.log("user clicked the pause button");
   * });
   */
  pause: void;
  /**
   * Fires when the ValuePicker's play button is clicked.
   *
   * @since 5.0
   * @example
   * const valuePicker = new ValuePicker();
   * valuePicker.on("play", () => {
   *   console.log("user clicked the play button");
   * });
   */
  play: void;
  /**
   * Fires when the ValuePicker's previous button is clicked.
   *
   * @since 5.0
   * @example
   * const valuePicker = new ValuePicker();
   * valuePicker.on("previous", () => {
   *   console.log("user clicked the previous button");
   * });
   */
  previous: void;
}